--
-- Table structure for table `recall_history`
--

DROP TABLE IF EXISTS `recall_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `recall_history` (
  `recall_id` int NOT NULL AUTO_INCREMENT COMMENT '리콜 고유 ID',
  `model_id` int NOT NULL COMMENT '대상 모델 ID (FK)',
  `recall_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '리콜 번호',
  `component` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '결함 장치',
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '리콜 사유 상세',
  `repair_method` text COLLATE utf8mb4_unicode_ci COMMENT '시정 방법',
  `target_production_start_date` date NOT NULL COMMENT '대상 차량 생산 시작일',
  `target_production_end_date` date NOT NULL COMMENT '대상 차량 생산 종료일',
  `recall_start_date` date NOT NULL COMMENT '리콜 시작일',
  `recall_end_date` date DEFAULT NULL COMMENT '리콜 종료 예정일',
  `target_count` int DEFAULT '0' COMMENT '대상 총 대수',
  `recall_status` enum('active','completed','scheduled') COLLATE utf8mb4_unicode_ci DEFAULT 'active' COMMENT '진행 상태',
  `correction_rate` decimal(5,2) DEFAULT '0.00' COMMENT '시정률 (%)',
  `data_source` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '데이터 출처',
  `source_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '원본 링크',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`recall_id`),
  KEY `idx_production_range` (`target_production_start_date`,`target_production_end_date`),
  KEY `fk_recall_model` (`model_id`),
  CONSTRAINT `fk_recall_model` FOREIGN KEY (`model_id`) REFERENCES `vehicle_models` (`model_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6810 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

